import{_ as a,o as e,c as d,ag as i}from"./chunks/framework.CAXxHpAX.js";const c=JSON.parse('{"title":"第 22 章 Dify 应用和 Agent","description":"","frontmatter":{},"headers":[],"relativePath":"ml/ai-agent.md","filePath":"ml/ai-agent.md","lastUpdated":1777721040000}'),n={name:"ml/ai-agent.md"};function l(r,t,p,s,o,h){return e(),d("div",null,[...t[0]||(t[0]=[i(`<h1 id="第-22-章-dify-应用和-agent" tabindex="-1">第 22 章 Dify 应用和 Agent <a class="header-anchor" href="#第-22-章-dify-应用和-agent" aria-label="Permalink to &quot;第 22 章 Dify 应用和 Agent&quot;">​</a></h1><p>Dify 是一个用于构建大模型应用的平台。它把模型调用、提示词、知识库、工作流、工具调用和应用发布整合到一起，适合快速搭建聊天助手、知识库问答、工作流应用和 Agent 应用。</p><p>Agent 是大模型应用的一种形态。普通聊天助手主要回答问题，Agent 更强调“闭环执行”：能理解目标、拆解任务、调用工具、观察结果，并根据反馈继续行动。</p><h2 id="_22-1-相关链接" tabindex="-1">22.1 相关链接 <a class="header-anchor" href="#_22-1-相关链接" aria-label="Permalink to &quot;22.1 相关链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资源</th><th>地址</th></tr></thead><tbody><tr><td>Dify 官网</td><td><a href="https://dify.ai" target="_blank" rel="noreferrer">https://dify.ai</a></td></tr><tr><td>Dify 文档</td><td><a href="https://docs.dify.ai" target="_blank" rel="noreferrer">https://docs.dify.ai</a></td></tr><tr><td>Dify GitHub</td><td><a href="https://github.com/langgenius/dify" target="_blank" rel="noreferrer">https://github.com/langgenius/dify</a></td></tr></tbody></table><p>如果只是了解 Dify 能做什么，先看官网；如果要搭建应用，主要看官方文档。</p><h2 id="_22-2-dify-能做什么" tabindex="-1">22.2 Dify 能做什么 <a class="header-anchor" href="#_22-2-dify-能做什么" aria-label="Permalink to &quot;22.2 Dify 能做什么&quot;">​</a></h2><p>Dify 可以理解为大模型应用的编排平台。</p><p>常见能力：</p><table tabindex="0"><thead><tr><th>能力</th><th>作用</th></tr></thead><tbody><tr><td>模型接入</td><td>统一调用不同大模型</td></tr><tr><td>Prompt 编排</td><td>管理系统提示词、变量和上下文</td></tr><tr><td>知识库</td><td>上传文档，构建 RAG 问答</td></tr><tr><td>Workflow / Chatflow</td><td>用节点方式编排应用流程</td></tr><tr><td>Tools</td><td>接入搜索、API、数据库等外部能力</td></tr><tr><td>Agent</td><td>让模型自主选择工具并完成多步任务</td></tr><tr><td>API 发布</td><td>把应用发布成接口或 Web 应用</td></tr></tbody></table><p>Dify 的价值不在于发明新的模型，而在于把大模型应用需要的组件整理成可配置、可部署的工程系统。</p><h2 id="_22-3-dify-应用类型" tabindex="-1">22.3 Dify 应用类型 <a class="header-anchor" href="#_22-3-dify-应用类型" aria-label="Permalink to &quot;22.3 Dify 应用类型&quot;">​</a></h2><p>Dify 中常见应用形态包括：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>Chatbot</td><td>面向对话的助手</td></tr><tr><td>Agent</td><td>能使用工具的智能体</td></tr><tr><td>Workflow</td><td>按固定流程执行任务</td></tr><tr><td>Chatflow</td><td>面向对话场景的流程编排</td></tr><tr><td>Text Generator</td><td>文本生成类应用</td></tr></tbody></table><p>如果任务流程固定，适合用 Workflow；如果任务需要模型自己判断下一步该调用什么工具，适合用 Agent。</p><h2 id="_22-4-workflow-和-agent-的区别" tabindex="-1">22.4 Workflow 和 Agent 的区别 <a class="header-anchor" href="#_22-4-workflow-和-agent-的区别" aria-label="Permalink to &quot;22.4 Workflow 和 Agent 的区别&quot;">​</a></h2><p>Workflow 更像流程图。开发者明确规定每一步做什么：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入 -&gt; 知识库检索 -&gt; LLM 总结 -&gt; 输出</span></span></code></pre></div><p>Agent 更像带工具的执行者。开发者提供目标、工具和约束，模型在运行时决定怎么做：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户目标 -&gt; 模型思考 -&gt; 选择工具 -&gt; 观察结果 -&gt; 继续行动 -&gt; 输出</span></span></code></pre></div><p>对比：</p><table tabindex="0"><thead><tr><th>类型</th><th>控制方式</th><th>适合场景</th></tr></thead><tbody><tr><td>Workflow</td><td>人预先设计流程</td><td>稳定、固定、可控的业务流程</td></tr><tr><td>Agent</td><td>模型动态决定步骤</td><td>多步推理、工具选择、开放任务</td></tr></tbody></table><p>Workflow 的优点是稳定、可解释、便于调试；Agent 的优点是灵活，但结果更依赖模型能力和工具描述。</p><h2 id="_22-5-agent-的基本组成" tabindex="-1">22.5 Agent 的基本组成 <a class="header-anchor" href="#_22-5-agent-的基本组成" aria-label="Permalink to &quot;22.5 Agent 的基本组成&quot;">​</a></h2><p>一个典型 Agent 系统通常包含：</p><table tabindex="0"><thead><tr><th>模块</th><th>作用</th></tr></thead><tbody><tr><td>Planner</td><td>拆解目标，决定下一步行动</td></tr><tr><td>Tool</td><td>执行具体动作，例如搜索、查数据库、调用 API</td></tr><tr><td>Memory</td><td>保存历史状态、用户偏好和上下文</td></tr><tr><td>Observation</td><td>接收工具返回结果</td></tr><tr><td>Reflection</td><td>检查结果是否满足目标，不满足则调整</td></tr></tbody></table><p>这些模块不一定都由独立组件实现。它们更像 Agent 系统里的职责划分。</p><h2 id="_22-6-dify-中的-agent" tabindex="-1">22.6 Dify 中的 Agent <a class="header-anchor" href="#_22-6-dify-中的-agent" aria-label="Permalink to &quot;22.6 Dify 中的 Agent&quot;">​</a></h2><p>Dify 的 Agent 重点在于工具调用。模型不只是生成文本，还可以根据任务需要选择工具、填写参数、读取工具返回结果，再继续推理。</p><p>一个简化流程：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入</span></span>
<span class="line"><span>-&gt; Agent 理解目标</span></span>
<span class="line"><span>-&gt; 判断是否需要工具</span></span>
<span class="line"><span>-&gt; 调用工具</span></span>
<span class="line"><span>-&gt; 读取工具结果</span></span>
<span class="line"><span>-&gt; 继续推理或生成最终回答</span></span></code></pre></div><p>Agent 能不能稳定工作，主要取决于：</p><ul><li>工具描述是否清楚。</li><li>工具参数是否明确。</li><li>Prompt 是否给出任务边界。</li><li>最大迭代次数是否合理。</li><li>工具返回结果是否容易被模型理解。</li></ul><h2 id="_22-7-工具调用" tabindex="-1">22.7 工具调用 <a class="header-anchor" href="#_22-7-工具调用" aria-label="Permalink to &quot;22.7 工具调用&quot;">​</a></h2><p>工具让 Agent 从“只会回答”变成“可以做事”。</p><p>常见工具：</p><table tabindex="0"><thead><tr><th>工具</th><th>用途</th></tr></thead><tbody><tr><td>搜索工具</td><td>获取外部信息</td></tr><tr><td>HTTP API</td><td>调用业务系统</td></tr><tr><td>数据库查询</td><td>查询结构化数据</td></tr><tr><td>代码执行</td><td>计算或处理数据</td></tr><tr><td>知识库检索</td><td>从私有文档中找答案</td></tr></tbody></table><p>工具调用需要注意权限。凡是会修改数据、发消息、下单、删除文件的工具，都应该加权限控制、日志和人工确认。</p><h2 id="_22-8-知识库和-rag" tabindex="-1">22.8 知识库和 RAG <a class="header-anchor" href="#_22-8-知识库和-rag" aria-label="Permalink to &quot;22.8 知识库和 RAG&quot;">​</a></h2><p>RAG 是 Retrieval-Augmented Generation，检索增强生成。它的基本流程是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户问题 -&gt; 向量检索 -&gt; 召回文档 -&gt; 重排序 -&gt; 拼接上下文 -&gt; 生成回答</span></span></code></pre></div><p>Dify 的知识库适合做企业文档问答、产品手册问答、制度查询、客服知识库等场景。</p><p>RAG 的目的不是让模型参数记住所有知识，而是回答前先查外部资料。这样可以提高时效性，也能减少幻觉。</p><h2 id="_22-9-embedding-和-reranker" tabindex="-1">22.9 Embedding 和 Reranker <a class="header-anchor" href="#_22-9-embedding-和-reranker" aria-label="Permalink to &quot;22.9 Embedding 和 Reranker&quot;">​</a></h2><p>Embedding 模型负责把问题和文档转成向量，用于快速召回相似内容。</p><p>Reranker 负责对召回结果重新排序，判断哪些文档和问题最相关。</p><p>常见流程：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Embedding 粗召回 -&gt; Reranker 精排 -&gt; LLM 生成回答</span></span></code></pre></div><p>Embedding 解决“先找一批可能相关的文档”，Reranker 解决“从候选文档里挑最相关的”。</p><h2 id="_22-10-openclaw-架构" tabindex="-1">22.10 OpenClaw 架构 <a class="header-anchor" href="#_22-10-openclaw-架构" aria-label="Permalink to &quot;22.10 OpenClaw 架构&quot;">​</a></h2><p>OpenClaw 是一种 Agent 系统架构示例，可以用来理解 Agent 应用怎样拆分职责。</p><p>题库中提到的 OpenClaw 核心架构有四个角色：</p><table tabindex="0"><thead><tr><th>角色</th><th>作用</th></tr></thead><tbody><tr><td>GateKeeper</td><td>多渠道指令接收与身份验证</td></tr><tr><td>Planner</td><td>负责任务拆解与决策规划</td></tr><tr><td>Worker</td><td>提供基础操作能力和具体任务方法</td></tr><tr><td>Memory</td><td>实现用户偏好和对话历史的持久化存储</td></tr></tbody></table><p>可以按一句话记忆：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GateKeeper 管入口，Planner 管计划，Worker 管执行，Memory 管长期状态。</span></span></code></pre></div><p>Dify 更偏应用编排平台，OpenClaw 更偏 Agent 运行架构。二者关注点不同，但都在解决同一个问题：怎样把大模型、工具、记忆和任务流程组织成可用系统。</p><h2 id="_22-11-dify-适合的场景" tabindex="-1">22.11 Dify 适合的场景 <a class="header-anchor" href="#_22-11-dify-适合的场景" aria-label="Permalink to &quot;22.11 Dify 适合的场景&quot;">​</a></h2><p>Dify 更适合搭建应用，而不是训练模型。</p><p>适合场景：</p><ul><li>企业知识库问答。</li><li>客服助手。</li><li>内部流程自动化。</li><li>报表总结。</li><li>文档处理。</li><li>低代码 AI 应用原型。</li><li>带工具调用的 Agent 应用。</li></ul><p>不太适合的场景：</p><ul><li>从零训练大模型。</li><li>极复杂的后端业务系统。</li><li>对执行结果要求极高但缺少校验机制的自动化任务。</li></ul><h2 id="_22-12-dify-和传统开发的关系" tabindex="-1">22.12 Dify 和传统开发的关系 <a class="header-anchor" href="#_22-12-dify-和传统开发的关系" aria-label="Permalink to &quot;22.12 Dify 和传统开发的关系&quot;">​</a></h2><p>Dify 可以降低大模型应用的搭建成本，但不能完全替代后端开发。</p><p>可以把 Dify 理解成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>大模型应用编排层</span></span></code></pre></div><p>它适合负责：</p><ul><li>LLM 调用。</li><li>Prompt 管理。</li><li>知识库检索。</li><li>Agent 工具编排。</li><li>应用原型搭建。</li></ul><p>传统后端仍然适合负责：</p><ul><li>用户系统。</li><li>权限控制。</li><li>复杂业务逻辑。</li><li>数据一致性。</li><li>支付、订单等高风险操作。</li></ul><p>实际项目中，常见做法是 Dify 负责 AI 能力编排，业务系统负责核心数据和权限。</p>`,71)])])}const b=a(n,[["render",l]]);export{c as __pageData,b as default};
